import { GoogleLogin } from "@react-oauth/google";
import { jwtDecode } from "jwt-decode";
import React, { useState, useContext } from "react";
import { Link, useNavigate } from "react-router-dom";
import { AuthContext } from "../context/AuthContext";

const Login = () => {
  const [mode, setMode] = useState("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [subscribeNewsletter, setSubscribeNewsletter] = useState(true);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const navigate = useNavigate();
  const { login, register, setUser } = useContext(AuthContext);

  // -------------------------------------------
  // ⭐ FACEBOOK LOGIN (KHÔNG SDK – CHUẨN OAUTH)
  // -------------------------------------------
  const handleFacebookLogin = () => {
    const FACEBOOK_APP_ID = "1180477920674027";

    const redirectUri = "http://localhost:3000/auth/facebook/callback";

    const url =
      `https://www.facebook.com/v19.0/dialog/oauth?` +
      `client_id=${FACEBOOK_APP_ID}` +
      `&redirect_uri=${encodeURIComponent(redirectUri)}` +
      `&state=dtp_flowershop` +
      `&response_type=token` +
      `&scope=email,public_profile`;

    window.location.href = url;
  };

  // -------------------------------------------
  // ⭐ LOGIN THƯỜNG
  // -------------------------------------------
  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    const result = await login(email, password);

    if (result?.success) {
      navigate(result.user.role === "admin" ? "/admin" : "/");
    } else {
      setError(result?.message || "Sai thông tin đăng nhập!");
    }

    setLoading(false);
  };

  // -------------------------------------------
  // ⭐ REGISTER THƯỜNG
  // -------------------------------------------
  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    const result = await register(
      name,
      email,
      password,
      "",
      "",
      subscribeNewsletter
    );

    if (result?.success) navigate("/");
    else setError(result?.message || "Đăng ký thất bại.");

    setLoading(false);
  };

  // -------------------------------------------
  // ⭐ GOOGLE LOGIN
  // -------------------------------------------
  const handleGoogleLogin = async (credentialResponse) => {
    try {
      const decoded = jwtDecode(credentialResponse.credential);

      const res = await fetch(
        "http://localhost:5000/api/auth/google-login",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            email: decoded.email,
            name: decoded.name,
            googleId: decoded.sub,
            picture: decoded.picture,
          }),
        }
      );

      const data = await res.json();

      if (data.success) {
        const userToSave = {
          _id: data.user._id,
          name: data.user.name,
          email: data.user.email,
          role: data.user.role,
          picture: data.user.picture,
          token: data.accessToken,
        };

        localStorage.setItem("userInfo", JSON.stringify(userToSave));
        setUser(userToSave);

        navigate(userToSave.role === "admin" ? "/admin" : "/");
      } else {
        setError("Không thể đăng nhập bằng Google.");
      }
    } catch (err) {
      console.error(err);
      setError("Lỗi Google Login!");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#faf8f6] px-4 py-10">
      <div className="w-full max-w-md bg-white shadow-lg rounded-2xl border border-[#f2e4e0] p-8">
        <h2 className="text-center text-2xl font-semibold text-[#e06c7f] mb-6">
          {mode === "login" ? "🌸 Đăng nhập tài khoản" : "🌷 Tạo tài khoản mới"}
        </h2>

        {error && (
          <div className="bg-red-100 text-red-700 p-3 rounded-lg mb-4 text-center">
            ⚠️ {error}
          </div>
        )}

        {mode === "login" ? (
          <>
            <form onSubmit={handleLogin}>
              <input
                type="email"
                placeholder="Email"
                className="w-full mb-3 p-3 border rounded-lg"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />

              <div className="relative mb-6">
                <input
                  type={showPassword ? "text" : "password"}
                  placeholder="Mật khẩu"
                  className="w-full p-3 pr-10 border rounded-lg"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-3"
                >
                  {showPassword ? "🙈" : "👁️"}
                </button>
              </div>

              <button className="w-full bg-[#e06c7f] text-white py-3 rounded-lg">
                {loading ? "Đang đăng nhập..." : "Đăng nhập"}
              </button>

              {/* Divider */}
              <div className="flex items-center my-4">
                <div className="flex-grow h-px bg-gray-300"></div>
                <span className="px-3 text-gray-500 text-sm">hoặc</span>
                <div className="flex-grow h-px bg-gray-300"></div>
              </div>

              {/* GOOGLE */}
              <div className="flex justify-center mb-3">
                <GoogleLogin
                  onSuccess={handleGoogleLogin}
                  onError={() => setError("Đăng nhập Google thất bại!")}
                />
              </div>

              {/* FACEBOOK */}
              <div className="flex justify-center">
                <button
                  onClick={handleFacebookLogin}
                  type="button"
                  className="bg-blue-600 text-white w-full py-3 rounded-lg hover:bg-blue-700"
                >
                  Đăng nhập bằng Facebook 💙
                </button>
              </div>

              <div className="text-center mt-4 text-sm">
                <Link
                  onClick={() => setMode("register")}
                  className="text-[#e06c7f]"
                >
                  ✨ Chưa có tài khoản? Đăng ký ngay
                </Link>
              </div>
            </form>
          </>
        ) : (
          <>
            <form onSubmit={handleRegister}>
              <input
                type="text"
                placeholder="Họ tên"
                className="w-full mb-3 p-3 border rounded-lg"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />

              <input
                type="email"
                placeholder="Email"
                className="w-full mb-3 p-3 border rounded-lg"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />

              <input
                type="password"
                placeholder="Mật khẩu"
                className="w-full mb-3 p-3 border rounded-lg"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />

              <label className="flex items-center mb-5 text-sm">
                <input
                  type="checkbox"
                  checked={subscribeNewsletter}
                  onChange={(e) => setSubscribeNewsletter(e.target.checked)}
                  className="mr-2"
                />
                📧 Nhận tin khuyến mãi & ưu đãi
              </label>

              <button className="w-full bg-[#e06c7f] text-white py-3 rounded-lg">
                {loading ? "Đang đăng ký..." : "Đăng ký tài khoản"}
              </button>

              {/* Divider */}
              <div className="flex items-center my-4">
                <div className="flex-grow h-px bg-gray-300"></div>
                <span className="px-3 text-gray-500 text-sm">hoặc</span>
                <div className="flex-grow h-px bg-gray-300"></div>
              </div>

              {/* GOOGLE */}
              <div className="flex justify-center mb-3">
                <GoogleLogin
                  onSuccess={handleGoogleLogin}
                  onError={() => setError("Đăng ký Google thất bại!")}
                />
              </div>

              {/* FACEBOOK */}
              <div className="flex justify-center">
                <button
                  onClick={handleFacebookLogin}
                  type="button"
                  className="bg-blue-600 text-white w-full py-3 rounded-lg hover:bg-blue-700"
                >
                  Đăng ký bằng Facebook 💙
                </button>
              </div>

              <div className="text-center mt-4 text-sm">
                <Link
                  onClick={() => setMode("login")}
                  className="text-[#e06c7f]"
                >
                  🔙 Đã có tài khoản? Quay lại đăng nhập
                </Link>
              </div>
            </form>
          </>
        )}
      </div>
    </div>
  );
};

export default Login;
